"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import Link from "next/link";
import { ICase } from "@/models/Case";

export default function UserDashboard() {
    const { user, isLoading: authLoading } = useAuth();
    const router = useRouter();
    const [cases, setCases] = useState<ICase[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (!authLoading && !user) {
            router.push("/login");
        }
    }, [user, authLoading, router]);

    useEffect(() => {
        const fetchCases = async () => {
            try {
                const response = await fetch("/api/cases");
                if (response.ok) {
                    const data = await response.json();
                    setCases(data);
                } else {
                    console.error("Failed to load cases");
                }
            } catch (error) {
                console.error("Error fetching cases:", error);
            } finally {
                setLoading(false);
            }
        };

        if (user) {
            fetchCases();
        }
    }, [user]);

    if (authLoading || loading) {
        return (
            <div className="flex justify-center items-center min-h-screen">
                <p className="text-xl">Loading dashboard...</p>
            </div>
        );
    }

    if (!user) {
        return null; // Will redirect
    }

    return (
        <div className="container mx-auto p-8">
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-3xl font-bold">User Dashboard</h1>
                    <p className="text-gray-600">Welcome, {user.name}</p>
                </div>
                <Link
                    href="/dashboard/cases/new"
                    className="bg-blue-600 text-white px-4 py-2 rounded-md hover:bg-blue-700 transition"
                >
                    Create New Case
                </Link>
            </div>

            <div className="bg-white rounded-lg shadow-md p-6">
                <h2 className="text-xl font-semibold mb-4">Your Cases</h2>

                {cases.length === 0 ? (
                    <div className="text-center py-12 text-gray-500">
                        <p>Nothing to show here</p>
                        <p className="text-sm mt-2">Create a new case to get started.</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {cases.map((c) => (
                            <Link href={`/dashboard/cases/${c._id as unknown as string}`} key={c._id as unknown as string}>
                                <div className="border rounded-md p-4 hover:shadow-lg transition cursor-pointer h-full flex flex-col">
                                    <h3 className="font-bold text-lg mb-2">{c.title}</h3>
                                    <p className="text-gray-600 text-sm mb-4 flex-grow line-clamp-3">
                                        {c.description}
                                    </p>
                                    <div className="flex justify-between items-center text-xs mt-auto">
                                        <span
                                            className={`px-2 py-1 rounded-full ${c.status === "Open"
                                                ? "bg-green-100 text-green-800"
                                                : c.status === "Closed"
                                                    ? "bg-gray-100 text-gray-800"
                                                    : "bg-yellow-100 text-yellow-800"
                                                }`}
                                        >
                                            {c.status}
                                        </span>
                                        <span className="text-gray-500">
                                            {new Date(c.createdAt).toLocaleDateString()}
                                        </span>
                                    </div>
                                </div>
                            </Link>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}
